document.addEventListener("DOMContentLoaded",function(){var t=document.querySelectorAll(".account-nav__item"),c=document.querySelectorAll(".account-section");t.length&&c.length&&t.forEach(function(e){e.addEventListener("click",function(e){e.preventDefault();e=this.dataset.section,t.forEach(function(e){e.classList.remove("is-active")}),c.forEach(function(e){e.classList.remove("is-active")}),this.classList.add("is-active"),e=document.querySelector('.account-section[data-section="'+e+'"]');e&&e.classList.add("is-active")})});document.querySelectorAll(".account-order").forEach(function(e){var t=e.querySelector(".account-order__toggle");t&&t.addEventListener("click",function(){e.classList.toggle("is-open")})});var e=document.querySelector(".account-profile-form");e&&e.addEventListener("submit",function(e){e.preventDefault(),console.log("profile saved")})});